const fastify = require('fastify')({ logger: true });
const crypto = require('crypto');

// Register fastify-raw-body to get the raw request body for signature verification
fastify.register(require('fastify-raw-body'), {
  field: 'rawBody',
  global: true,
  encoding: 'utf8',
  runFirst: true,
});

fastify.post('/webhook', async (request, reply) => {
  const signature = request.headers['x-prembly-signature'];
  const apiKey = process.env.PREMBLY_API_KEY;

  if (!apiKey) {
    request.log.error('PREMBLY_API_KEY environment variable is not set');
    return reply.status(500).send({ error: 'Configuration error' });
  }

  if (!signature) {
    return reply.status(401).send({ error: 'Invalid signature' });
  }

  // Compute HMAC-SHA256 signature
  const hmac = crypto.createHmac('sha256', apiKey);
  hmac.update(request.rawBody);
  const computedSignature = hmac.digest('base64');

  // Compare signatures
  if (computedSignature !== signature) {
    request.log.warn({
      msg: 'Signature mismatch',
      received: signature,
      computed: computedSignature
    });
    return reply.status(401).send({ error: 'Invalid signature' });
  }

  // Signature is valid, process the webhook
  request.log.info('Webhook signature verified successfully');
  return reply.status(200).send({ status: 'received' });
});

const start = async () => {
  try {
    await fastify.listen({ port: 3000, host: '0.0.0.0' });
    console.log('Server listening on port 3000');
  } catch (err) {
    fastify.log.error(err);
    process.exit(1);
  }
};

start();

